import { IMessageComposer } from '@nitrots/nitro-renderer';

export class DeleteInventoryItemComposer implements IMessageComposer<any[]>
{
private _data: any[];

constructor(invRowId: number, amount: number = 1)
{
this._data = [ invRowId, amount ];
}

public getMessageArray(): any[]
{
return this._data;
}

public dispose(): void
{
return;
}
}